	/// <summary>
	/// Describes some basic details about a playback or capture device.<br/>
	/// </summary>
	#if NET5_0_OR_GREATER
	[DebuggerDisplay("{DebuggerDisplay,nq}")]
	#endif
	public unsafe struct MaDeviceDescriptorPtr : IEquatable<MaDeviceDescriptorPtr>
	{
		public MaDeviceDescriptorPtr(MaDeviceDescriptor* handle) { Handle = handle; }

		public MaDeviceDescriptor* Handle;

		public bool IsNull => Handle == null;

		public static MaDeviceDescriptorPtr Null => new MaDeviceDescriptorPtr(null);

		public MaDeviceDescriptor this[int index] { get => Handle[index]; set => Handle[index] = value; }

		public static implicit operator MaDeviceDescriptorPtr(MaDeviceDescriptor* handle) => new MaDeviceDescriptorPtr(handle);

		public static implicit operator MaDeviceDescriptor*(MaDeviceDescriptorPtr handle) => handle.Handle;

		public static bool operator ==(MaDeviceDescriptorPtr left, MaDeviceDescriptorPtr right) => left.Handle == right.Handle;

		public static bool operator !=(MaDeviceDescriptorPtr left, MaDeviceDescriptorPtr right) => left.Handle != right.Handle;

		public static bool operator ==(MaDeviceDescriptorPtr left, MaDeviceDescriptor* right) => left.Handle == right;

		public static bool operator !=(MaDeviceDescriptorPtr left, MaDeviceDescriptor* right) => left.Handle != right;

		public bool Equals(MaDeviceDescriptorPtr other) => Handle == other.Handle;

		/// <inheritdoc/>
		public override bool Equals(object obj) => obj is MaDeviceDescriptorPtr handle && Equals(handle);

		/// <inheritdoc/>
		public override int GetHashCode() => ((nuint)Handle).GetHashCode();

		#if NET5_0_OR_GREATER
		private string DebuggerDisplay => string.Format("MaDeviceDescriptorPtr [0x{0}]", ((nuint)Handle).ToString("X"));
		#endif
		public ref MaDeviceIdPtr PDeviceID => ref Unsafe.AsRef<MaDeviceIdPtr>(&Handle->PDeviceID);
		public ref MaShareMode ShareMode => ref Unsafe.AsRef<MaShareMode>(&Handle->ShareMode);
		public ref MaFormat Format => ref Unsafe.AsRef<MaFormat>(&Handle->Format);
		public ref uint Channels => ref Unsafe.AsRef<uint>(&Handle->Channels);
		public ref uint SampleRate => ref Unsafe.AsRef<uint>(&Handle->SampleRate);
		public unsafe Span<byte> ChannelMap
		
		{
			get
			{
				return new Span<byte>(&Handle->ChannelMap_0, 254);
			}
		}
		public ref uint PeriodSizeInFrames => ref Unsafe.AsRef<uint>(&Handle->PeriodSizeInFrames);
		public ref uint PeriodSizeInMilliseconds => ref Unsafe.AsRef<uint>(&Handle->PeriodSizeInMilliseconds);
		public ref uint PeriodCount => ref Unsafe.AsRef<uint>(&Handle->PeriodCount);
	}

